if let Some(scheduled) = eth_tx.as_scheduled() {
    let scheduled = scheduled.tx();
    if !is_heartbeat_tx(scheduled.to) {
        fulfilled.insert((scheduled.call_id, scheduled.index));
    }
}
if let Some(commitment) = eth_tx.as_async_commitment() {
    if let Ok(OriginalTransaction::Scheduled(signed)) = commitment.tx().decode_original_transaction() {
        let scheduled = signed.tx();
        if !is_heartbeat_tx(scheduled.to) {
            fulfilled.insert((scheduled.call_id, scheduled.index));
        }
    }
}

for obligation in &obligations {
    if fulfilled.contains(&(obligation.call_id, obligation.index)) { continue; }
    if obligation_has_active_async_job(...) { continue; }
    if gas_remaining >= required_gas {
        return Err(BlockVerificationError::ScheduledTransactionCensored { ... });
    }
}
